Replace pick(pool) at line 104 with a dedup-aware selector:
  function pickDeduped<T>(arr: readonly T[]): T {
    if (arr.length <= 1) return arr[0];
    let idx: number;
    let tries = 0;
    do { idx = Math.floor(Math.random() * arr.length); tries++; } while (_recentIndices.includes(idx) && tries < 5);
    _recentIndices.push(idx);
    if (_recentIndices.length > 3) _recentIndices.shift();
    return arr[idx];
  }
